def dedupe_events(events: list[Event]) -> list[Event]:
    seen: dict[str, Event] = {}
    unique: list[Event] = []
    for event in events:
        previous = seen.get(event.event_id)
        if previous is None:
            seen[event.event_id] = event
            unique.append(event)
        elif previous != event:
            raise ValueError("conflicting duplicate event id")
    return unique
