{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/event_parser.py","content":"import json
import re
from collections.abc import Mapping

from event_models import Event
from event_time import parse_timestamp


_IDENTIFIER_RE = re.compile(r"[A-Za-z0-9][A-Za-z0-9._-]*")
_AMOUNT_RE = re.compile(r"[0-9]+(?:\.[0-9]{1,2})?")
_EVENT_KEYS = {"id", "user", "kind", "amount", "timestamp"}


def _reject_nonstandard_constant(value: str) -> object:
    raise ValueError(f"invalid JSON numeric constant: {value}")


def _identifier(value: object, *, label: str) -> str:
    if not isinstance(value, str) or _IDENTIFIER_RE.fullmatch(value) is None:
        raise ValueError(f"invalid {label}")
    return value


def _amount_cents(value: object) -> int:
    if not isinstance(value, str) or _AMOUNT_RE.fullmatch(value) is None:
        raise ValueError("invalid amount")
    whole, separator, fraction = value.partition(".")
    amount_cents = int(whole) * 100
    if separator:
        amount_cents += int(fraction.ljust(2, "0"))
    if amount_cents <= 0:
        raise ValueError("amount must be positive")
    return amount_cents


def parse_jsonl(text: str) -> list[Event]:
    if not isinstance(text, str):
        raise ValueError("jsonl_text must be a string")
    events: list[Event] = []
    for line in text.splitlines():
        if not line.strip():
            continue
        try:
            raw = json.loads(line, parse_constant=_reject_nonstandard_constant)
        except (json.JSONDecodeError, ValueError) as exc:
            raise ValueError("invalid event line") from exc
        if not isinstance(raw, Mapping) or set(raw) != _EVENT_KEYS:
            raise ValueError("event must contain exactly the required keys")
        kind = raw["kind"]
        if kind not in {"credit", "debit"}:
            raise ValueError("invalid event kind")
        events.append(
            Event(
                event_id=_identifier(raw["id"], label="id"),
                user=_identifier(raw["user"], label="user"),
                kind=kind,
                amount_cents=_amount_cents(raw["amount"]),
                timestamp=parse_timestamp(raw["timestamp"]),
            )
        )
    return events
